import React, { useState, useEffect } from 'react'

const Taskcard = ({ task, handleDeleteTask }) => {
    const [subtasks, setSubtasks] = useState([])

    function addtask() {
        const newtask = {
            activity: '',
            id: crypto.randomUUID(),
            completed: false
        };

        setSubtasks(prev => {
            const updated = [...prev, newtask];
            localStorage.setItem('tasks', JSON.stringify(updated)); // ✅ Save full array
            return updated;
        });
    }


    function handleSubtaskChange(id, value) {
        setSubtasks(prev => {
            const updated = prev.map(sub =>
                sub.id === id ? { ...sub, activity: value } : sub
            );
            localStorage.setItem('tasks', JSON.stringify(updated)); // ✅ Save updated list
            return updated;
        });
    }


    function handleCheckbox(id, subcompleted) {
        setSubtasks(prev => {
            const updated = prev.map(sub =>
                sub.id === id ? { ...sub, completed: !subcompleted } : sub
            );
            localStorage.setItem('tasks', JSON.stringify(updated)); // ✅ Save updated list
            return updated;
        });
    }

    useEffect(() => {
        const storedTasks = localStorage.getItem('tasks');
        if (storedTasks) {
            setSubtasks(JSON.parse(storedTasks));
        }
    }, []);

    function handleBlur(id, value) {
        if (value.trim() === '') {
            setSubtasks(prev => prev.filter(sub => sub.id !== id))
        }
    }
    function autoResizeTextarea(e) {
        e.target.style.height = 'auto';
        e.target.style.height = e.target.scrollHeight + 'px';
    }
    function autoResize(e) {
        e.target.style.height = 'auto'; // reset
        e.target.style.height = e.target.scrollHeight + 'px'; // grow to content
    }


    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>
                        {task.title}
                    </div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' onClick={addtask}>
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button onClick={() => handleDeleteTask(task.id)} className='icon-button'>
                                <img className='icon-img' src='./assets/delete.png' alt="Delete" />
                            </button>
                        </div>
                    </div>
                </div>

                <div className='sub-tasks'>
                    {subtasks.map((sub) => (
                        <div className='sub-task-items' key={sub.id}>
                            <div style={{ display: 'flex', width: '100%' }}>
                                <input
                                    type='checkbox'
                                    onClick={() => handleCheckbox(sub.id, sub.completed)}
                                    className='subtask-checkbox'
                                />
                                <textarea
                                    className={`subtask-input ${sub.completed ? 'subtask-checked' : ''}`}
                                    value={sub.activity}
                                    onChange={(e) => {
                                        handleSubtaskChange(sub.id, e.target.value);
                                        autoResize(e); // 👈 auto-grow
                                    }}
                                    onInput={autoResize}
                                    onBlur={(e) => handleBlur(sub.id, e.target.value)}
                                    placeholder="Enter sub task"
                                    autoFocus
                                    rows={1}
                                />

                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <style>{`
        .task-card {
          padding: 10px;
          background-color: var(--secondary-color);
          border-radius: 5px;
          box-sizing: border-box;
          display: flex;
          flex-direction: column;
          width: 100%;
          max-width: 300px; /* Allow multiple cards in row */
        }

        .taskcard-header {
          display: flex;
          align-items: center;
          justify-content: space-between;
          padding: 5px;
          flex-direction: row;
        }

        .task-icons {
          display: flex;
          align-items: center;
        }

        .icon-button {
          background: none;
          border: none;
          cursor: pointer;
        }

        .icon-img {
          height: 20px;
          width: 30px;
        }

        .task-title {
          width: 100px;
          word-wrap: break-word;
          overflow-wrap: break-word;
          white-space: normal;
        }

        .sub-tasks {
          display: flex;
          flex-direction: column;
          margin-top: 10px;
        }

        .sub-task-items {
          width: 100%;
          display: flex;
          align-items: flex-start;
          margin-bottom: 5px;
        }

       .subtask-input {
  width: 100%;
  min-height: 30px;
  resize: none;
  overflow: hidden;
  padding: 8px;
  border: none;
  background-color: var(--secondary-color);
  color: var(--text);
  font-family: 'Cedarville Cursive', cursive;
  font-size: 1rem;
  line-height: 1.4;
  box-sizing: border-box;
  border-radius: 4px;
}



        .subtask-checked {
          text-decoration: line-through;
          opacity: 0.6;
        }


        .subtask-checkbox {
  appearance: none;
  -webkit-appearance: none;
  height: 20px;
  width: 20px;
  border: 2px solid var(--text);
  border-radius: 4px;
  cursor: pointer;
  margin-right: 8px;
  background-color: transparent;
  position: relative;
}

/* When checked, change background */
.subtask-checkbox:checked {
  background-color: var(--secondary-color);
  border-color: var(--text);
}

/* Optional: add custom checkmark (✓) */
.subtask-checkbox:checked::after {
  content: '✓';
  color: var(--text);
  font-size: 14px;
  position: absolute;
  top: -2px;
  left: 2px;
  border-color: var(--secondary-color);
}

      `}</style>
        </>
    )
}

export default Taskcard
